-- Dati ricostruiti dai monitoraggi EEA Italia 2010-2025. La tabella e
-- separata dai profili originali: non sovrascrive representative_year,
-- year_from o year_to inseriti nel database del socio.

BEGIN;

CREATE TABLE IF NOT EXISTS mvp.vehicle_cluster_years_v1 (
  vehicle_cluster_id text PRIMARY KEY,
  year_from integer NOT NULL,
  year_to integer NOT NULL,
  estimation_method text NOT NULL,
  confidence text NOT NULL,
  matched_rows_count integer NOT NULL,
  historical_registrations_count bigint NOT NULL,
  matched_historical_years integer[] NOT NULL,
  source_name text NOT NULL,
  source_url text NOT NULL,
  built_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT vehicle_cluster_years_v1_years_check CHECK (
    year_from BETWEEN 1900 AND 2100
    AND year_to BETWEEN year_from AND 2100
  ),
  CONSTRAINT vehicle_cluster_years_v1_confidence_check CHECK (
    confidence IN ('high', 'medium_high', 'medium', 'medium_low', 'low')
  )
);

TRUNCATE TABLE mvp.vehicle_cluster_years_v1;

