,"historical_registrations_count":0,"matched_historical_years":[]},{"vehicle_cluster_id":"f99ffc2fce4a744c0815a3ea4b716de7","year_from":2025,"year_to":2025,"method":"first_observed_in_current_eea","confidence":"low","matched_rows_count":0,"historical_registrations_count":0,"matched_historical_years":[]},{"vehicle_cluster_id":"38093783615793c8544ec2a00515de74","year_from":2025,"year_to":2025,"method":"first_observed_in_current_eea","confidence":"low","matched_rows_count":0,"historical_registrations_count":0,"matched_historical_years":[]},{"vehicle_cluster_id":"5bfaf0c9c58cc3c9ecae1613287c905b","year_from":2025,"year_to":2025,"method":"first_observed_in_current_eea","confidence":"low","matched_rows_count":0,"historical_registrations_count":0,"matched_historical_years":[]},{"vehicle_cluster_id":"0bae53ef449a555f0abb9bb0e2b84600","year_from":2025,"year_to":2025,"method":"first_observed_in_current_eea","confidence":"low","matched_rows_count":0,"historical_registrations_count":0,"matched_historical_years":[]},{"vehicle_cluster_id":"0e8a891d046b4cf9b2dd56df2d6187b1","year_from":2024,"year_to":2025,"method":"exact_model_powertrain_power_tvv_confirmed","confidence":"high","matched_rows_count":1,"historical_registrations_count":11,"matched_historical_years":[2024]}]$years$::jsonb AS data
), rows AS (
  SELECT item
  FROM payload
  CROSS JOIN LATERAL jsonb_array_elements(data) AS elements(item)
)
INSERT INTO mvp.vehicle_cluster_years_v1 (
  vehicle_cluster_id,
  year_from,
  year_to,
  estimation_method,
  confidence,
  matched_rows_count,
  historical_registrations_count,
  matched_historical_years,
  source_name,
  source_url
)
SELECT
  item ->> 'vehicle_cluster_id',
  (item ->> 'year_from')::integer,
  (item ->> 'year_to')::integer,
  item ->> 'method',
  item ->> 'confidence',
  (item ->> 'matched_rows_count')::integer,
  (item ->> 'historical_registrations_count')::bigint,
  ARRAY(
    SELECT value::integer
    FROM jsonb_array_elements_text(item -> 'matched_historical_years') AS years(value)
  ),
  'EEA CO2 monitoring - immatricolazioni italiane 2010-2025',
  'https://www.eea.europa.eu/en/datahub/datahubitem-view/fa8b1229-3db6-495d-b18e-9c9b3267c02b'
FROM rows;

COMMENT ON TABLE mvp.vehicle_cluster_years_v1 IS
'Anno iniziale osservato per ciascun cluster del catalogo sito, ricostruito sulle serie EEA Italia 2010-2025. Non sostituisce gli anni originali dei profili.';

CREATE OR REPLACE FUNCTION public.auto_tco_versions(p_model_id text)
RETURNS jsonb
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = pg_catalog, public
AS $function$
  SELECT jsonb_build_object(
    'items',
    COALESCE(
      jsonb_agg(
        to_jsonb(item)
        ORDER BY
          item.display_year DESC,
          item.registrations_count DESC,
          item.fuel_type,
          item.power_cv NULLS LAST,
          item.vehicle_cluster_id
      ),
      '[]'::jsonb
    )
  )
  FROM (
    SELECT
      catalog.vehicle_cluster_id,
      catalog.model_catalog_id,
      catalog.vehicle_profile_id,
      catalog.seed_model_id,
      catalog.brand,
      catalog.model,
      catalog.version_label,
      profile.representative_year,
      CASE
        WHEN profile.representative_year IS NOT NULL
          AND profile.profile_kind <> 'recent_wltp_2025'
          AND COALESCE(profile.source_type, '') <> 'eea_wltp_2025_curated'
          THEN profile.representative_year
        ELSE years.year_from
      END AS display_year,
      years.year_from AS observed_year_from,
      years.year_to AS observed_year_to,
      CASE
        WHEN profile.representative_year IS NOT NULL
          AND profile.profile_kind <> 'recent_wltp_2025'
          AND COALESCE(profile.source_type, '') <> 'eea_wltp_2025_curated'
          THEN 'original_database'
        ELSE years.estimation_method
      END AS year_source,
      CASE
        WHEN profile.representative_year IS NOT NULL
          AND profile.profile_kind <> 'recent_wltp_2025'
          AND COALESCE(profile.source_type, '') <> 'eea_wltp_2025_curated'
          THEN 'original'
        ELSE years.confidence
      END AS year_confidence,
      catalog.fuel_type,
      catalog.hybrid_type,
      catalog.powertrain_type,
      catalog.power_kw,
      catalog.power_cv,
      catalog.energy_data_status,
      catalog.depreciation_data_status,
      catalog.observation_quality,
      catalog.registrations_count
    FROM mvp.site_vehicle_catalog_eea_v2 AS catalog
    LEFT JOIN mvp.vehicle_profiles AS profile
      ON profile.id = catalog.vehicle_profile_id
    JOIN mvp.vehicle_cluster_years_v1 AS years
      ON years.vehicle_cluster_id = catalog.vehicle_cluster_id
    WHERE catalog.model_catalog_id = left(trim(p_model_id), 64)
      AND catalog.model_key NOT IN (
        'UNKNOWN', 'UNK', 'NA', 'NULL', 'NOTAVAILABLE'
      )
      AND catalog.model_key <> 'GV80GENESISGV80'
  ) AS item;
$function$;

REVOKE ALL ON FUNCTION public.auto_tco_versions(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.auto_tco_versions(text) TO anon;

COMMIT;

-- Verifica inclusa: deve terminare con verifica = ok.
WITH valid_catalog AS (
  SELECT catalog.*
  FROM mvp.site_vehicle_catalog_eea_v2 AS catalog
  WHERE catalog.model_key NOT IN ('UNKNOWN', 'UNK', 'NA', 'NULL', 'NOTAVAILABLE')
    AND catalog.model_key <> 'GV80GENESISGV80'
), resolved AS (
  SELECT
    catalog.vehicle_cluster_id,
    catalog.model_catalog_id,
    catalog.brand,
    catalog.model,
    catalog.version_label,
    catalog.registrations_count,
    years.year_from,
    years.estimation_method,
    years.confidence,
    CASE
      WHEN profile.representative_year IS NOT NULL
        AND profile.profile_kind <> 'recent_wltp_2025'
        AND COALESCE(profile.source_type, '') <> 'eea_wltp_2025_curated'
        THEN profile.representative_year
      ELSE years.year_from
    END AS display_year
  FROM valid_catalog AS catalog
  LEFT JOIN mvp.vehicle_profiles AS profile
    ON profile.id = catalog.vehicle_profile_id
  LEFT JOIN mvp.vehicle_cluster_years_v1 AS years
    ON years.vehicle_cluster_id = catalog.vehicle_cluster_id
), duplicates AS (
  SELECT
    model_catalog_id,
    display_year,
    version_label,
    count(*) AS occurrences
  FROM resolved
  GROUP BY model_catalog_id, display_year, version_label
  HAVING count(*) > 1
), formentor AS (
  SELECT
    display_year,
    estimation_method,
    confidence
  FROM resolved
  WHERE brand = 'Cupra'
    AND model = 'Formentor'
    AND version_label ILIKE 'Plug-in%150 CV%'
  ORDER BY registrations_count DESC
  LIMIT 1
)
SELECT
  (SELECT count(*) FROM valid_catalog) AS versioni_catalogo,
  (SELECT count(*) FROM mvp.vehicle_cluster_years_v1) AS anni_ricostruiti,
  count(*) FILTER (WHERE display_year IS NOT NULL) AS versioni_con_anno,
  count(*) FILTER (WHERE display_year IS NULL) AS versioni_senza_anno,
  count(*) FILTER (WHERE year_from < 2025) AS con_storia_precedente_al_2025,
  count(*) FILTER (WHERE year_from = 2025) AS osservate_dal_2025,
  (SELECT count(*) FROM duplicates) AS etichette_duplicate,
  (SELECT display_year FROM formentor) AS anno_formentor_plugin_150,
  (SELECT estimation_method FROM formentor) AS metodo_formentor,
  CASE
    WHEN (SELECT count(*) FROM valid_catalog) = count(*)
      AND count(*) = count(*) FILTER (WHERE display_year IS NOT NULL)
      AND count(*) FILTER (WHERE display_year IS NULL) = 0
      AND (SELECT count(*) FROM duplicates) = 0
      AND (SELECT display_year FROM formentor) = 2021
      THEN 'ok'
    ELSE 'controllare'
  END AS verifica
FROM resolved;
